import{_ as c,r,o as d,c as p,a as e,b as t,t as i,d as o,w as l,e as h}from"./app-d223f2a5.js";const w={},y={id:"frontmatter-title-관련",tabindex:"-1"},f=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),m={class:"table-of-contents"},_=e("hr",null,null,-1),g=e("h2",{id:"project-8-part-three",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#project-8-part-three","aria-hidden":"true"},"#"),t(" Project 8, part three")],-1),k=e("p",null,"There are many well-known quotes from Shakespeare, but there’s one I think is particularly apt today: “the fool doth think he is wise, but the wise man knows himself to be a fool.” I don’t know where you’d rank yourself in terms of Auto Layout knowledge, but I hope you’re at least aware that it’s a really big, complex space to work in!",-1),b={href:"http://vimeo.com/291590798",target:"_blank",rel:"noopener noreferrer"},v=e("p",null,"Fortunately for all of us, this part of your Auto Layout learning is complete, so it’s time for us to review what you’ve learned.",-1),j=e("p",null,[e("strong",null,"Today you should work through the wrap up chapter for project 8, complete its review, then work through all three of its challenges.")],-1),x=e("h3",{id:"wrap-up",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#wrap-up","aria-hidden":"true"},"#"),t(" Wrap up")],-1),I={class:"hint-container details"},T=e("summary",null,"Wrap up",-1),O={href:"https://www.hackingwithswift.com/read/8/6/wrap-up",target:"_blank",rel:"noopener noreferrer"},S=h('<p>Yes, it took quite a lot of user interface code to get this project going, but I hope it has shown you that you can make some great games using just the UIKit tools you already know. Building user interfaces programmatically is obviously much less visual than using storyboards, but the flip side is that everything is under your control – there are no connections happening behind the scenes.</p><p>Of course, at the same time as making another game, you&#39;ve made several steps forward in your iOS development journey, this time learning about <code>addTarget()</code>, <code>enumerated()</code>, <code>joined()</code>, <code>replacingOccurrences()</code>, and more.</p><h4 id="review-what-you-learned" tabindex="-1"><a class="header-anchor" href="#review-what-you-learned" aria-hidden="true">#</a> Review what you learned</h4><p>Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.</p>',4),A={href:"https://www.hackingwithswift.com/review/hws/project-8-7-swifty-words",target:"_blank",rel:"noopener noreferrer"},L=h('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try extending this app to make sure you fully understand what’s going on:</p><ol><li>Use the techniques you learned in project 2 to draw a thin gray line around the buttons view, to make it stand out from the rest of the UI.</li><li>If the user enters an incorrect guess, show an alert telling them they are wrong. You’ll need to extend the <code>submitTapped()</code> method so that if <code>firstIndex(of:)</code> failed to find the guess you show the alert.</li><li>Try making the game also deduct points if the player makes an incorrect guess. Think about how you can move to the next level – we can’t use a simple division remainder on the player’s <code>score</code> any more, because they might have lost some points.</li></ol>',3),N={class:"hint-container info"},W=e("p",{class:"hint-container-title"},"Wrap up - Additional",-1),Y={href:"https://www.hackingwithswift.com/review/hws/project-8-7-swifty-words",target:"_blank",rel:"noopener noreferrer"},q=e("p",null,"Once you’re done, tell other people: you’ve built another great app for iOS, and you’ve learned how to build a complete user interface entirely in code.",-1),B=e("p",null,"You should be proud of what you’ve accomplished – keep it up!",-1);function C(n,V){const s=r("router-link"),a=r("ExternalLinkIcon"),u=r("YouTube");return d(),p("div",null,[e("h1",y,[f,t(" "+i(n.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,i(n.$frontmatter.description),1)]),e("nav",m,[e("ul",null,[e("li",null,[o(s,{to:"#project-8-part-three"},{default:l(()=>[t("Project 8, part three")]),_:1}),e("ul",null,[e("li",null,[o(s,{to:"#wrap-up"},{default:l(()=>[t("Wrap up")]),_:1})])])])])]),_,g,k,e("p",null,[t("In my "),e("a",b,[t("talk at NSSpain 2018"),o(a)]),t(" I said “Auto Layout makes hard things easy, and easy things hard” – you’ll find you can do relatively advanced layouts like today’s in about an hour, but occasionally you’ll find yourself wanting one specific layout constraint that is really hard to get right.")]),v,j,x,e("details",I,[T,e("p",null,[e("a",O,[t("📎link"),o(a)])]),o(u,{id:"cODcGmJM-OQ"}),S,e("p",null,[e("a",A,[t("Click here to review what you learned in project 8."),o(a)])]),L]),e("div",N,[W,e("ul",null,[e("li",null,[e("a",Y,[t("Review for Project 8: 7 Swifty Words"),o(a)])])])]),q,B])}const P=c(w,[["render",C],["__file","38.html.vue"]]);export{P as default};
